To generate a sample CSV file for testing, you can manually create a text file and save it with a `.csv` extension. Here's a sample CSV file:

```
Column1,Column2,Column3
Value1-1,Value1-2,Value1-3
Value2-1,Value2-2,Value2-3
Value3-1,Value3-2,Value3-3
Value1-1,Value1-2,Value1-3
Value4-1,Value4-2,Value4-3
```

Save the file as `sample.csv` and make sure it is in the same directory as the HTML file you're using for the Find Duplicates functionality.

Alternatively, you can use the following JavaScript code to generate a sample CSV file dynamically:

```javascript
function generateSampleCSV() {
  const csvContent = "Column1,Column2,Column3\nValue1-1,Value1-2,Value1-3\nValue2-1,Value2-2,Value2-3\nValue3-1,Value3-2,Value3-3\nValue1-1,Value1-2,Value1-3\nValue4-1,Value4-2,Value4-3";
  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const link = document.createElement('a');
  link.href = URL.createObjectURL(blob);
  link.download = 'sample.csv';
  link.click();
}

// Call this function to generate and download the sample CSV file
generateSampleCSV();
```

You can add this code snippet to your HTML file and execute the `generateSampleCSV()` function to download the sample CSV file named `sample.csv`.

Apologies for the inconvenience. Here's an updated version of the code with the proper Tailwind CSS CDN link:

```html
<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Find Duplicates</title>
    <link href="https://cdn.jsdelivr.net/npm/tailwindcss@2.2.15/dist/tailwind.min.css" rel="stylesheet">
</head>
<body class="bg-gray-100 py-6 px-4">
    <div class="max-w-xl mx-auto bg-white rounded-lg p-6 shadow">
        <input type="file" id="csvFile" accept=".csv" class="mb-4">
        <label for="columnName" class="block mb-2">Column Name:</label>
        <input type="text" id="columnName" class="w-full rounded-lg p-2 mb-4">
        <button onclick="findDuplicates()" class="bg-blue-500 hover:bg-blue-600 text-white rounded-lg py-2 px-4">Find Duplicates</button>
    </div>

    <script>
        /**
         * Function to find duplicates in a CSV file based on a specified column.
         */
        function findDuplicates() {
            // Get the selected CSV file and column name
            const csvFile = document.getElementById('csvFile').files[0];
            const columnName = document.getElementById('columnName').value;

            // Validate if both file and column name are provided
            if (csvFile && columnName) {
                const reader = new FileReader();
                reader.onload = function (event) {
                    const csv = event.target.result;
                    const lines = csv.split('\n');
                    const headers = lines[0].split(',');

                    // Find the index of the specified column name
                    const columnIndex = headers.indexOf(columnName);
                    if (columnIndex === -1) {
                        alert('Column not found!');
                        return;
                    }

                    const values = [];
                    for (let i = 1; i < lines.length; i++) {
                        if (lines[i].trim() !== '') {
                            const data = lines[i].split(',');
                            values.push(data[columnIndex]);
                        }
                    }

                    // Find the duplicates in the column values
                    const duplicates = values.filter((value, index, self) => self.indexOf(value) !== index);

                    // Display the results
                    if (duplicates.length === 0) {
                        alert('No duplicates found!');
                    } else {
                        alert('Duplicates found:\n' + duplicates.join(', '));
                    }
                };
                reader.readAsText(csvFile, 'UTF-8');
            } else {
                alert('Please select a CSV file and enter a column name!');
            }
        }
    </script>
</body>
</html>
```

